const errorData = $input.first().json;

const execution = errorData.execution || {};
const error = execution.error || {};
const lastNode = execution.lastNodeExecuted || 'Desconocido';
const workflowName = execution.workflowData?.name || 'APA Flujo Formulario Web';
const workflowId = execution.workflowData?.id || 'N/A';
const executionId = execution.id || 'N/A';
const errorMessage = error.message || 'Sin mensaje de error';
const errorDescription = error.description || '';
const errorStack = error.stack || '';
const timestamp = new Date().toLocaleString('es-AR', { timeZone: 'America/Argentina/Buenos_Aires' });

return [{
  json: {
    workflow_name: workflowName,
    workflow_id: workflowId,
    execution_id: executionId,
    nodo_fallido: lastNode,
    error_mensaje: errorMessage,
    error_descripcion: errorDescription,
    error_stack: errorStack.substring(0, 500),
    timestamp: timestamp,
    severidad: 'ERROR'
  }
}];
